import React, { useContext } from 'react'
import { Expander, ExpanderContent, ExpanderHeader, List, ListItem, Paragraph } from '@fs/zion-ui'
import { css } from '@linaria/core'
import GeneralistListItem from './GeneralistListItem'
import { filterGeneralistsByLanguage } from './helpers'
import FilterOverlay from './FilterOverlay'
import { helperContext } from './HelperProvider'

const someCss = css`
  /* please don't delete these again, we did it on purpose to meet designs. Ask Ryan if you have questions. */
  max-height: 300px;
  overflow-y: auto;
  overflow-x: hidden;
  padding-bottom: 10px;
`

const Generalists = () => {
  const context = useContext(helperContext)
  const { generalists, totalAvailable, setGeneralistsOpen, generalistsOpen, generalistsLangFilter } = context || {}
  const showMessage = totalAvailable > (generalists?.length ?? 0)
  const numberToShow = totalAvailable - (generalists?.length ?? 0)
  const generalistsToDisplay = generalists?.filter((gen) => filterGeneralistsByLanguage(gen, generalistsLangFilter))
  return (
    <>
      <List>
        <FilterOverlay />
      </List>
      <Expander open={generalistsOpen} setOpen={setGeneralistsOpen}>
        <ExpanderHeader>
          <Paragraph size="xs">Available ({totalAvailable || 0})</Paragraph>
        </ExpanderHeader>
        <ExpanderContent>
          <div className={someCss}>
            <List>
              {generalistsToDisplay?.map((info, i) => {
                const k = `${info?.available}${i}`
                return <GeneralistListItem key={k} {...info} />
              })}
              {showMessage && (
                <ListItem
                  dense
                  startElement={<ListItem.Filler />}
                  primaryText={`... ${numberToShow} other helpers not shown`}
                  secondaryText="(Waiting for a shorter time period)"
                />
              )}
            </List>
          </div>
        </ExpanderContent>
      </Expander>
    </>
  )
}

export default Generalists
