import React, { useContext } from 'react'
import { ListItem, H6 } from '@fs/zion-ui'
import { ControlView } from '@fs/zion-icon'
import { discussionTimeStampToString, getLangMapping } from './helpers'
import { helperContext } from './HelperProvider'

const MyStatus = () => {
  const context = useContext(helperContext)
  const { myStatus, setAvailable, userProfile } = context || {}
  const { available } = myStatus || {}

  let availabilityString = 'Unavailable'
  if (available) {
    availabilityString = `Available ${discussionTimeStampToString(available)}`
  }

  return (
    <>
      <H6>You</H6>
      <ListItem
        data-testid="helper-current-status"
        startElement={<ListItem.Avatar monogram={userProfile?.name?.value?.[0]} />}
        primaryText={`${userProfile?.name?.value} - ${availabilityString}`}
        secondaryText={myStatus?.languages
          ?.split(',')
          .map((lang) => getLangMapping(lang.trim()))
          .join(', ')}
        endElement={
          <ListItem.IconButton
            data-testid="helper-availability-toggle"
            Icon={ControlView}
            title="Toggle Availability"
            iconToggle={Boolean(!myStatus?.available)}
            onClick={setAvailable}
          />
        }
      />
    </>
  )
}

export default MyStatus
