import React from 'react'
import { useUserProfile } from '@fs/zion-user'
import { ListItem, Skeleton, useOverlay } from '@fs/zion-ui'
import { ContactOverlay } from '@fs/zion-contact-overlay'
import { discussionTimeStampToString, getLangMapping } from './helpers'

const GeneralistListItem = ({ generalistCisId, languages, available }) => {
  const { userProfile, userProfileLoading, error } = useUserProfile(generalistCisId)
  const overlay = useOverlay()

  const availableSinceString = discussionTimeStampToString(available)

  if (userProfileLoading) return <Skeleton.ListItem hasSecondLine />

  if (error) return null

  return (
    <>
      <ListItem
        dense
        startElement={<ListItem.Avatar monogram={userProfile?.name?.value?.[0]} />}
        primaryText={`${userProfile?.name?.value} ${availableSinceString}`}
        secondaryText={languages
          .split(',')
          .map((lang) => getLangMapping(lang.trim()))
          .join(', ')}
        onClick={overlay.handleClick}
      />
      <ContactOverlay contact={{ cisId: generalistCisId }} overlay={overlay} disableAbout />
    </>
  )
}

export default GeneralistListItem
