import React, { useContext } from 'react'
import { PlaceWorld } from '@fs/zion-icon'
import { DialogOverlay, CheckboxList, ListItem, colors } from '@fs/zion-ui'
import { getLangMapping } from './helpers'
import { helperContext } from './HelperProvider'

const FilterOverlay = () => {
  const context = useContext(helperContext)
  const { myStatus = {}, generalistsLangFilter, setGeneralistsLangFilter, filterOverlay = {} } = context || {}
  const { userLangs } = myStatus
  const areFiltersOn = userLangs?.length !== generalistsLangFilter?.length
  return (
    <>
      <ListItem
        data-testid="filter-langs-button"
        dense
        primaryText={`Filter Helpers by Language ${areFiltersOn ? '(on)' : ''}`}
        onClick={filterOverlay?.handleClick}
        endElement={<ListItem.Icon Icon={PlaceWorld} color={areFiltersOn ? colors.green40 : colors.gray100} />}
      />
      <DialogOverlay title="Choose Which Languages To Display" {...filterOverlay}>
        <CheckboxList
          initialSelection={generalistsLangFilter}
          selectAllLabel="Select All"
          onSelectionChange={setGeneralistsLangFilter}
        >
          {userLangs?.map((lang, i) => {
            const k = `${lang}${i}`
            return <ListItem key={k} name={lang} primaryText={getLangMapping(lang)} />
          })}
        </CheckboxList>
      </DialogOverlay>
    </>
  )
}

export default FilterOverlay
