import React, { useContext } from 'react'
import { css } from '@linaria/core'
import { formatValue } from '@fs/zion-locale'
import { Paragraph, colors, Separator, H6 } from '@fs/zion-ui'
import { helperContext } from './HelperProvider'

const blueCss = css`
  color: ${colors.blue30};
  font-size: 20px;
  font-weight: 700;
`

const Statistics = () => {
  const context = useContext(helperContext)
  const { stats } = context || {}
  const { averageWaitTimeSec = 0, generalistPeopleHelped = 0, totalPeopleHelped = 0 } = stats || {}

  return (
    <>
      <H6>Your Statistics</H6>
      <Paragraph size="xs">
        You&apos;ve helped <span className={blueCss}>{formatValue(generalistPeopleHelped)}</span> People
      </Paragraph>
      <Separator size="sm" />
      <H6>Team Statistics</H6>
      <Paragraph size="xs">
        <span className={blueCss}>{formatValue(totalPeopleHelped)}</span> Total People Helped
      </Paragraph>
      <Paragraph size="xs">
        <span className={blueCss}>{formatValue(averageWaitTimeSec)}s</span> Average Wait Time
      </Paragraph>
    </>
  )
}

export default Statistics
