import { useCallback, useContext } from 'react'
import { useStatusOverlay } from '@fs/zion-ui'
import { useHistory } from '@fs/zion-router'
import { helperContext } from '../chat-helper-tab/HelperProvider'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import { assignDiscussion } from '../services/helperQueue/helperQueueService'
import { CHAT_ACTIONS } from './useChatReducer'
import { updateChannelInChannels } from '../helpers/stream/streamChatHelper'
import { addMembers } from '../services/fsChat/fsChatService'
import chatLog, { LOG_LEVEL } from '../global/chatLog'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'
import useHandleChatErrors from './useHandleChatErrors'

const useAuaDiscussion = () => {
  const context = useContext(helperContext)
  const { myStatus } = context || {}
  const { available } = myStatus || {}
  const history = useHistory()
  const { channels, client, user } = useChatState()
  const showStatusOverlay = useStatusOverlay()
  const chatDispatch = useChatDispatch()
  const { handleBasicError } = useHandleChatErrors()

  return useCallback(
    async ({ badgeCount, lang }) => {
      const cisId = user?.cisId
      let cid = null

      const handleDiscussion = async () => {
        if (!badgeCount) return
        if (client && cisId && available) {
          let assignedDiscussion
          try {
            const response = await assignDiscussion(cisId, lang)
            assignedDiscussion = response.data
          } catch (e) {
            chatLog({
              component: 'useAuaDiscussion',
              msg: `Failed to assign discussion for cisId: ${cisId}, lang: ${lang}. Error: ${e}`,
              level: LOG_LEVEL.ERROR,
              user,
            })
            if (e?.response?.status === 404) {
              showStatusOverlay({ message: 'No discussions are currently available', transient: true })
              return
            }
            throw e
          }

          if (!assignedDiscussion?.roomJid) {
            chatLog({
              component: 'useAuaDiscussion',
              msg: `assignDiscussion returned invalid data for cisId: ${cisId}. Response: ${JSON.stringify(assignedDiscussion)}`,
              level: LOG_LEVEL.ERROR,
              user,
            })
            throw new Error('Invalid assignDiscussion response - missing roomJid')
          }

          cid = assignedDiscussion.roomJid

          try {
            // Add the user as a member of the support channel before querying the channel, so they have required permissions.
            await addMembers({ cid, cisIds: [cisId] })
          } catch (e) {
            chatLog({
              component: 'useAuaDiscussion',
              msg: `Failed to add member. cisId: ${cisId}, cid: ${cid}. Error: ${e}. Response data: ${JSON.stringify(e?.response?.data)}`,
              level: LOG_LEVEL.ERROR,
              user,
            })
            throw e
          }

          try {
            const [channel] = await client.queryChannels({ cid: { $eq: cid } })
            if (channel) {
              chatDispatch({
                type: CHAT_ACTIONS.SET_CHANNELS,
                channels: updateChannelInChannels(channels, channel),
              })
              history.push(buildChatRoute(CHAT_ROUTE_KEY.CHAT, { cid: channel?.cid }))
            } else {
              chatLog({
                component: 'useAuaDiscussion',
                msg: `Channel not found after queryChannels. cisId: ${cisId}, cid: ${cid}`,
                level: LOG_LEVEL.ERROR,
                user,
              })
              showStatusOverlay({
                message: "We are sorry. We are unable to find the helper's Chat!",
                type: 'warning',
                transient: true,
                dismissable: true,
              })
            }
          } catch (e) {
            chatLog({
              component: 'useAuaDiscussion',
              msg: `Failed to query channels. cisId: ${cisId}, cid: ${cid}. Error: ${e}`,
              level: LOG_LEVEL.ERROR,
              user,
            })
            handleBasicError(e, {
              moreInfo: `Problem assigning AUA discussion. ChannelId: ${cid}`,
            })
          }
        } else if (!available && client) {
          showStatusOverlay({ message: 'Your status must be "available" to take chats', transient: true })
        } else if (!client) {
          chatLog({
            component: 'useAuaDiscussion',
            msg: `Client disconnected. cisId: ${cisId}`,
            level: LOG_LEVEL.ERROR,
            user,
          })

          showStatusOverlay({
            message: 'You have been disconnected, please refresh your browser',
            transient: true,
          })
        }
      }

      try {
        await handleDiscussion()
      } catch (e) {
        chatLog({
          component: 'useAuaDiscussion',
          msg: `Unhandled error in handleDiscussion. cisId: ${cisId}, cid: ${cid}. Error: ${e}`,
          level: LOG_LEVEL.ERROR,
          user,
        })
        showStatusOverlay({
          message: 'We are sorry. We were unable to join you into a support chat. Please try again Later.',
          transient: true,
        })
      }
    },
    [channels, chatDispatch, available, client, history, showStatusOverlay, user, handleBasicError]
  )
}

export default useAuaDiscussion
