import React, { useContext, useEffect, useRef, useState } from 'react'
import { ListItem, List, Ellipsis, IconButton, H6, Row } from '@fs/zion-ui'
import { Person, SocialChat, MediaVolume } from '@fs/zion-icon'
import { usePreference, setPreference } from '@fs/zion-preferences'
import { getLangMapping, discussionTimeStampToString } from './helpers'
import { helperContext } from './HelperProvider'
import useAuaDiscussionHandler from '../hooks/useAuaDiscussionHandler'
import { getMyGeneralist } from '../services/helperQueue/helperQueueService'
import { playNotifySound } from '../hooks/useSoundNotification'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import useChatLog from '../hooks/useChatLog'

import newMessageSoundHelper from '../assets/new-helper.mp3'

function shouldNotify(oldSet, newSet, userSpeaksLangs) {
  if (!oldSet || !newSet || !userSpeaksLangs) return false
  const preferredLang = ([lang]) => userSpeaksLangs.includes(lang)
  const add = (acc, [, discussion]) => acc + discussion.count
  const oldCount = Object.entries(oldSet).filter(preferredLang).reduce(add, 0)
  const newCount = Object.entries(newSet).filter(preferredLang).reduce(add, 0)
  return newCount > oldCount
}

function useLangsTheUserSpeaks() {
  const [langs, setLangs] = useState(null)
  const { log } = useChatLog({ component: '[Discussions]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  useEffect(() => {
    let isUnmounted = false

    const fetchLanguages = async () => {
      try {
        const {
          data: { languages },
        } = await getMyGeneralist()

        if (!isUnmounted) {
          setLangs((languages || '').split(',').map((lang) => lang.trim()))
        }
      } catch (err) {
        if (!isUnmounted) {
          handleBasicError(err, { moreInfo: 'Failed to fetch user languages' })
        }
      }
    }

    fetchLanguages()

    return () => {
      isUnmounted = true
    }
  }, [handleBasicError])
  return langs
}

// when there is a new person waiting for help, play the notification sound
function useNotificationWhenNewDiscussion(discussions, enabled) {
  const discussionRef = useRef(null)
  const userSpeaksLangs = useLangsTheUserSpeaks()
  useEffect(() => {
    if (enabled) {
      if (shouldNotify(discussionRef.current, discussions, userSpeaksLangs)) {
        playNotifySound(newMessageSoundHelper)
      }
      discussionRef.current = discussions
    }
  }, [discussions, enabled, userSpeaksLangs])
}

const Discussions = () => {
  const context = useContext(helperContext)
  const { discussions, myStatus } = context || {}
  const { userLangs } = myStatus || {}
  const discussionHandler = useAuaDiscussionHandler()

  const [soundOn, setSoundOn] = useState(false)
  const preferenceOn = usePreference('messaging.chat.helper.notificationSound')

  useEffect(() => {
    setSoundOn(preferenceOn)
  }, [preferenceOn])

  useNotificationWhenNewDiscussion(discussions, soundOn)

  return (
    <div style={{ maxWidth: '325px' }}>
      <Row alignY="middle" gutters="xs" guttersY="none">
        <H6>Waiting For Help</H6>
        <IconButton
          title="Toggle sound when new person is waiting"
          Icon={MediaVolume}
          size="md"
          iconToggle={!soundOn}
          onClick={() => {
            const soundOff = !soundOn
            setSoundOn(soundOff)
            setPreference('messaging.chat.helper.notificationSound', soundOff)
          }}
        />
      </Row>
      <List>
        {userLangs
          ?.slice()
          .sort((a, b) => {
            const aCount = discussions?.[a]?.count || 0
            const bCount = discussions?.[b]?.count || 0
            return bCount - aCount
          })
          .map((lang, i) => {
            const k = `${lang}${i}`
            const badgeCount = discussions?.[lang]?.count || 0
            const waitTime = discussionTimeStampToString(discussions?.[lang]?.longestWait, true)
            const waitTimeStr = waitTime ? `Wait Time: ${waitTime}` : ''
            const handler = () => discussionHandler({ badgeCount, lang })
            return (
              <ListItem
                key={k}
                debounce={10 * 1000}
                dense
                title="Start Chat with Attendee"
                onClick={handler}
                startElement={<ListItem.Icon Icon={Person} />}
                emphasized={Boolean(badgeCount)}
                badgeCount={badgeCount}
                primaryText={<Ellipsis>{getLangMapping(lang)}</Ellipsis>}
                secondaryText={<Ellipsis>{waitTimeStr}</Ellipsis>}
                endElement={
                  badgeCount > 0 && (
                    <ListItem.IconButton
                      data-testid={`take-chat-${lang}`}
                      Icon={SocialChat}
                      onClick={handler}
                      title={`Take a chat in ${getLangMapping(lang)}`}
                    />
                  )
                }
              />
            )
          })}
      </List>
    </div>
  )
}

export default Discussions
