import React from 'react'
import { Grid, useContainerWidth, Divider, Bleedable } from '@fs/zion-ui'
import { css } from '@linaria/core'
import Generalists from './Generalists'
import MyStatus from './MyStatus'
import Statistics from './Statistics'
import Discussions from './Discussions'

const scrollCss = css`
  overflow-y: auto;
  overflow-x: hidden;
`

export default function ChatHelperTab() {
  const atWidth = useContainerWidth()
  const mobile = atWidth({ default: true, md: false })
  return (
    <>
      {!mobile && (
        <Bleedable top={20} sides={12} className={scrollCss}>
          <Grid>
            <div columns={4}>
              <Statistics />
            </div>
            <div columns={4}>
              <Discussions />
            </div>
            <div columns={4}>
              <MyStatus />
              <Generalists />
            </div>
          </Grid>
        </Bleedable>
      )}
      {mobile && (
        <Bleedable top={20} sides={12} className={scrollCss}>
          <MyStatus />
          <Divider marginY="xs" />
          <Discussions />
          <Divider marginY="xs" />
          <Generalists />
          <Divider marginY="xs" />
          <Statistics />
        </Bleedable>
      )}
    </>
  )
}
